// figma-to-dtcg inline (no external imports in n8n Code node)
function figmaRgbToHex({ r, g, b }) {
  const toHex = (n) => Math.round(n * 255).toString(16).padStart(2, '0').toUpperCase();
  return `#${toHex(r)}${toHex(g)}${toHex(b)}`;
}
function pxToRem(px) { return `${px / 16}rem`; }
function setNested(obj, slashPath, value) {
  const parts = slashPath.split('/');
  let current = obj;
  for (let i = 0; i < parts.length - 1; i++) {
    if (!current[parts[i]]) current[parts[i]] = {};
    current = current[parts[i]];
  }
  current[parts[parts.length - 1]] = value;
}
const COLLECTION_FILE_MAP = { 'Brand': 'color.json', 'Spacing': 'spacing.json' };
const TYPE_MAP = { 'COLOR': 'color', 'FLOAT': 'dimension' };

const figmaData = $input.first().json;
if (!figmaData || !figmaData.collections) throw new Error('No collections in push payload');

const files = {};
for (const collection of figmaData.collections) {
  const fileName = COLLECTION_FILE_MAP[collection.name];
  if (!fileName) continue;
  const root = {};
  for (const variable of collection.variables) {
    let tokenValue;
    if (variable.type === 'COLOR') tokenValue = figmaRgbToHex(variable.value);
    else if (variable.type === 'FLOAT') tokenValue = pxToRem(variable.value);
    else tokenValue = variable.value;
    const token = { '$value': tokenValue, '$type': TYPE_MAP[variable.type] || variable.type };
    if (variable.description) token['$description'] = variable.description;
    setNested(root, variable.name, token);
  }
  files[fileName] = root;
}

return Object.entries(files).map(([filename, content]) => ({
  json: { filename, content: JSON.stringify(content, null, 2) }
}));

// Commit each transformed token file to the new branch via GitHub Contents API
const branchName = $node['Create Branch'].json.ref.replace('refs/heads/', '');
const owner = $env.GITHUB_OWNER;
const repo = $env.GITHUB_REPO;
const token = $env.GITHUB_TOKEN;
const files = $input.all().map(item => item.json);

const results = [];
for (const file of files) {
  // Get current SHA if the file already exists (required for updates)
  let existingSha = null;
  try {
    const getRes = await $http.request({
      method: 'GET',
      url: `https://api.github.com/repos/${owner}/${repo}/contents/tokens/${file.filename}`,
      headers: {
        'Authorization': `Bearer ${token}`,
        'Accept': 'application/vnd.github.v3+json'
      },
      qs: { ref: branchName }
    });
    existingSha = getRes.sha;
  } catch (e) {
    // File doesn't exist yet — that's fine, create it
  }

  const body = {
    message: `chore: sync ${file.filename} from Figma`,
    content: Buffer.from(file.content).toString('base64'),
    branch: branchName
  };
  if (existingSha) body.sha = existingSha;

  const putRes = await $http.request({
    method: 'PUT',
    url: `https://api.github.com/repos/${owner}/${repo}/contents/tokens/${file.filename}`,
    headers: {
      'Authorization': `Bearer ${token}`,
      'Accept': 'application/vnd.github.v3+json',
      'Content-Type': 'application/json'
    },
    body: JSON.stringify(body)
  });
  results.push({ filename: file.filename, sha: putRes.content.sha });
}

return [{ json: { branchName, committed: results } }];
